public class PaymentReminderService : BackgroundService
{
    private readonly IServiceScopeFactory _scopeFactory;

    public PaymentReminderService(IServiceScopeFactory scopeFactory)
    {
        _scopeFactory = scopeFactory;
    }

    protected override async Task ExecuteAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            using var scope = _scopeFactory.CreateScope();
            var reminderRepo = scope.ServiceProvider
                .GetRequiredService<IReminderRepository>();

            await reminderRepo.ProcessDueRemindersAsync();
            await Task.Delay(TimeSpan.FromHours(1), ct);
        }
    }
}

