// Worker Service — Generic Host (no AddControllersWithViews)
var host = Host.CreateDefaultBuilder(args)
    .ConfigureServices((ctx, services) =>
    {
        // Register background service
        services.AddHostedService<PaymentReminderWorker>();

        // All Singleton (no HTTP scope in worker)
        services.AddSingleton<IEmailService, SmtpEmailService>();
        services.AddSingleton<IConfigService, JsonConfigService>();

        // DbContext as Scoped (used via IServiceScopeFactory)
        services.AddDbContext<AppDbContext>(opts =>
            opts.UseSqlServer(ctx.Configuration.GetConnectionString("Default")));
    })
    .Build();

await host.RunAsync();

// Extension method groups registrations by concern
public static class ServiceCollectionExtensions
{
    public static IServiceCollection AddApplicationServices(this IServiceCollection services)
    {
        services.AddScoped<DashboardService>();
        services.AddScoped<InvestmentService>();
        services.AddScoped<PortfolioService>();
        return services; // fluent
    }

    public static IServiceCollection AddInfrastructure(
        this IServiceCollection services, IConfiguration config)
    {
        services.AddDbContext<AppDbContext>(o =>
            o.UseMySql(config.GetConnectionString("Default"),
                ServerVersion.AutoDetect(config.GetConnectionString("Default"))));

        services.AddHttpClient<MfApiService>();
        services.AddSingleton<FundHoldingsService>();
        return services;
    }
}

